from openai import OpenAI
from vex_sdk import PolicyVerifier

client = OpenAI()
verifier = PolicyVerifier('csirt-policy')

def validate_tool_call(tool_call):
    schema = {
        'type': 'object',
        'properties': {
            'action': {'enum': ['scan', 'isolate', 'notify']},
            'target': {'type': 'string', 'pattern': '^(?!192.168).*' }
        }
    }

    verdict = verifier.enforce_schema(tool_call, schema)
    if verdict.violations:
        return {'block': True, 'reason': 'Invalid security action'}
    return {'approved': True}

import OpenAI from 'openai';
import { VexClient } from '@vex/sdk';

const openai = new OpenAI({ apiKey: process.env.OPENAI_API_KEY });
const vex = new VexClient({ apiKey: process.env.VEX_API_KEY });

export async function handleRunComplete(event: any) {
  const run = await openai.beta.threads.runs.retrieve(
    event.data.thread_id,
    event.data.run_id
  );

  // Verify against CVE database
  const verification = await vex.verify({
    name: 'cve-validation',
    input: run.required_action?.submit_tool_outputs,
    context: { cve_db: 'https://cve.mitre.org/data/downloads/allitems.csv' }
  });

  if (!verification.passed) {
    await openai.beta.threads.runs.submit_tool_outputs(
      event.data.thread_id,
      event.data.run_id,
      [{ tool_call_id: 'tc_123', output: 'BLOCKED: Unverified CVE' }]
    );
    throw new Error('Compliance block');
  }
}
